import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { getMoodStats, getAssessmentHistory, getSessions } from '../api';

const TIPS = [
  "Take 5 deep breaths when you feel overwhelmed.",
  "A 20-minute walk can improve your mood significantly.",
  "Journaling for 10 minutes a day reduces anxiety.",
  "Talking to someone you trust is always a strength, not a weakness.",
  "Sleep is the most powerful mental health tool you have.",
  "You don't have to be okay all the time. It's okay to ask for help.",
];

export default function Dashboard() {
  const { user } = useAuth();
  const [stats, setStats] = useState(null);
  const [assessments, setAssessments] = useState([]);
  const [sessions, setSessions] = useState([]);
  const [tip] = useState(() => TIPS[Math.floor(Math.random() * TIPS.length)]);

  useEffect(() => {
    getMoodStats().then(r => setStats(r.data)).catch(() => {});
    getAssessmentHistory().then(r => setAssessments(r.data || [])).catch(() => {});
    getSessions().then(r => setSessions(r.data || [])).catch(() => {});
  }, []);

  const hour = new Date().getHours();
  const greeting = hour < 12 ? 'Good morning' : hour < 17 ? 'Good afternoon' : 'Good evening';

  const lastAssessment = assessments[0];

  return (
    <div style={styles.page}>
      {/* Header */}
      <div style={styles.header}>
        <div>
          <h1 style={styles.greeting}>{greeting}, {user?.name?.split(' ')[0]} 👋</h1>
          <p style={styles.date}>{new Date().toLocaleDateString('en-IN', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}</p>
        </div>
      </div>

      {/* Daily tip */}
      <div style={styles.tipCard}>
        <span style={styles.tipIcon}>✨</span>
        <div>
          <div style={styles.tipLabel}>Today's wellness tip</div>
          <div style={styles.tipText}>{tip}</div>
        </div>
      </div>

      {/* Stats */}
      <div style={styles.statsGrid}>
        <StatCard icon="😊" label="Avg Mood" value={stats?.avg_mood ? `${parseFloat(stats.avg_mood).toFixed(1)}/10` : '—'} color="var(--sage)" bg="var(--sage-pale)" />
        <StatCard icon="😰" label="Avg Stress" value={stats?.avg_stress ? `${parseFloat(stats.avg_stress).toFixed(1)}/5` : '—'} color="var(--amber)" bg="var(--amber-pale)" />
        <StatCard icon="😟" label="Avg Anxiety" value={stats?.avg_anxiety ? `${parseFloat(stats.avg_anxiety).toFixed(1)}/5` : '—'} color="var(--rose)" bg="var(--rose-pale)" />
        <StatCard icon="💬" label="Chat Sessions" value={sessions.length || '0'} color="var(--teal)" bg="var(--sage-pale)" />
      </div>

      {/* Quick actions */}
      <h2 style={styles.sectionTitle}>Quick Actions</h2>
      <div style={styles.actionsGrid}>
        <ActionCard to="/chat" icon="💬" title="Talk to MindEase" desc="Chat with your AI support companion" color="#EDF4F0" accent="var(--teal)" />
        <ActionCard to="/mood" icon="📊" title="Log Today's Mood" desc="Track how you're feeling right now" color="#FDF4EC" accent="var(--amber)" />
        <ActionCard to="/assessment" icon="📋" title="Take Assessment" desc="Check your mental health status" color="#FDEEF0" accent="var(--rose)" />
      </div>

      {/* Recent assessment */}
      {lastAssessment && (
        <div style={styles.recentSection}>
          <h2 style={styles.sectionTitle}>Last Assessment</h2>
          <div className="card" style={styles.assessmentCard}>
            <div style={styles.assessmentRow}>
              <div>
                <div style={styles.assessmentType}>{lastAssessment.assessment_type.toUpperCase()}</div>
                <div style={styles.assessmentDate}>{new Date(lastAssessment.taken_at).toLocaleDateString()}</div>
              </div>
              <div style={styles.assessmentRight}>
                <div style={styles.assessmentScore}>Score: {lastAssessment.score}</div>
                <span className={`badge badge-${lastAssessment.risk_level}`}>{lastAssessment.risk_level} risk</span>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Crisis resources */}
      <div style={styles.crisisBox}>
        <div style={styles.crisisTitle}>🆘 Need immediate help?</div>
        <div style={styles.crisisLines}>
          <span>iCall: <strong>9152987821</strong></span>
          <span>Vandrevala (24/7): <strong>1860-2662-345</strong></span>
          <span>NIMHANS: <strong>080-46110007</strong></span>
        </div>
      </div>
    </div>
  );
}

function StatCard({ icon, label, value, color, bg }) {
  return (
    <div className="card" style={{ ...styles.statCard, background: bg }}>
      <div style={{ fontSize: 28, marginBottom: 8 }}>{icon}</div>
      <div style={{ fontSize: '1.5rem', fontWeight: 700, color, fontFamily: 'var(--font-serif)' }}>{value}</div>
      <div style={{ fontSize: '0.82rem', color: 'var(--mist)', marginTop: 4 }}>{label}</div>
    </div>
  );
}

function ActionCard({ to, icon, title, desc, color, accent }) {
  return (
    <Link to={to} style={{ textDecoration: 'none' }}>
      <div className="card" style={{ ...styles.actionCard, background: color, borderColor: 'transparent' }}>
        <div style={{ fontSize: 32, marginBottom: 12 }}>{icon}</div>
        <div style={{ fontWeight: 700, fontSize: '1rem', color: accent, marginBottom: 4 }}>{title}</div>
        <div style={{ fontSize: '0.85rem', color: 'var(--mist)' }}>{desc}</div>
      </div>
    </Link>
  );
}

const styles = {
  page: { maxWidth: 900, margin: '0 auto' },
  header: { marginBottom: 24 },
  greeting: { fontSize: '2rem', color: 'var(--ink)' },
  date: { color: 'var(--mist)', fontSize: '0.9rem', marginTop: 4 },
  tipCard: {
    display: 'flex', alignItems: 'flex-start', gap: 14,
    background: 'linear-gradient(135deg, var(--teal-dark), var(--sage))',
    color: 'white', padding: '18px 22px', borderRadius: 'var(--radius)',
    marginBottom: 28,
  },
